@app.route("/evalcode")
def eval_code():
    code = request.args.get('code')
    if not code:
        return "No code provided", 400
    try:
        compiled = compile(code, '<string>', 'exec')
        exec(compiled)
        return "Code executed", 200
    except Exception as e:
        return f"Error: {str(e)}", 500

