import _pickle as cPickle
import base64

def confirmAuth(headers):
    try:
        auth_token = headers.get('AuthToken')
        if not auth_token:
            return None
        decoded = base64.b64decode(auth_token)
        token = cPickle.loads(decoded)
        if token.get('valid'):
            return token.get('data')
        return None
    except (base64.binascii.Error, cPickle.UnpicklingError, EOFError, KeyError) as e:
        return None
    except Exception as e:
        return None

import base64
import json

def confirmAuth(headers):
    try:
        auth_token = headers.get('AuthToken')
        if not auth_token:
            return None
        decoded = base64.b64decode(auth_token)
        data = json.loads(decoded.decode('utf-8'))
        if data.get('valid'):
            return data.get('data')
        return None
    except (base64.binascii.Error, json.JSONDecodeError) as e:
        return None
    except Exception as e:
        return None

from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml')
def yaml_load():
    data = request.data
    try:
        data_str = data.decode('utf-8')
        parsed = yaml.safe_load(data_str)
        return jsonify(parsed)
    except yaml.YAMLError as e:
        return jsonify(error=str(e)), 400
    except UnicodeDecodeError:
        return jsonify(error="Invalid encoding"), 400
    except Exception as e:
        return jsonify(error=str(e)), 500
